changeSet.sql:

-- hive_index_pattern: 'v11-log-suricata-*' → '_v3_hive_log-suricata-*'
UPDATE hive_index_pattern
SET pattern = REPLACE(pattern, 'v11-', '_v3_hive_')
WHERE pattern LIKE 'v11-%';

-- hive_menu: '&indexPattern=v11-log-*' → '&indexPattern=_v3_hive_log-*'
UPDATE hive_menu
SET url = REPLACE(url, '&indexPattern=v11-', '&indexPattern=_v3_hive_')
WHERE url LIKE '%&indexPattern=v11-%';

-- hive_correlation_rules: rule_after_events_def JSON: {"indexPattern":"v11-*"}
UPDATE hive_correlation_rules
SET rule_after_events_def = REPLACE(rule_after_events_def, '"indexPattern":"v11-', '"indexPattern":"_v3_hive_')
WHERE rule_after_events_def LIKE '%"indexPattern":"v11-%';

-- hive_dashboard: filters JSON column may reference v11- from migration 20251218002
UPDATE hive_dashboard
SET filters = REPLACE(filters, '"indexPattern":"v11-', '"indexPattern":"_v3_hive_')
WHERE filters LIKE '%"indexPattern":"v11-%';
